import { useEffect, useRef } from 'react'

const VIDEO_URL =
  'data:video/mp4;base64,'

let wakeAudioCtx: AudioContext | null = null
let wakeOsc: OscillatorNode | null = null
let wakeGain: GainNode | null = null

function startWakeAudio() {
  if (wakeAudioCtx) return
  try {
    wakeAudioCtx = new AudioContext()
    if (wakeAudioCtx.state === 'suspended') {
      wakeAudioCtx.resume().catch(() => {})
    }

    wakeGain = wakeAudioCtx.createGain()
    wakeGain.gain.value = 0.0001

    wakeOsc = wakeAudioCtx.createOscillator()
    wakeOsc.type = 'sine'
    wakeOsc.frequency.value = 19000

    wakeOsc.connect(wakeGain)
    wakeGain.connect(wakeAudioCtx.destination)
    wakeOsc.start()
  } catch {}
}

function stopWakeAudio() {
  try { wakeOsc?.stop() } catch {}
  try { wakeOsc?.disconnect() } catch {}
  wakeOsc = null
  try { wakeGain?.disconnect() } catch {}
  wakeGain = null
  try { wakeAudioCtx?.close() } catch {}
  wakeAudioCtx = null
}

function createWakeVideo(): HTMLVideoElement {
  const video = document.createElement('video')
  video.src = VIDEO_URL
  video.muted = true
  video.playsInline = true
  video.loop = true
  video.setAttribute('webkit-playsinline', '')
  video.setAttribute('disablePictureInPicture', '')
  Object.assign(video.style, {
    position: 'absolute',
    left: '-100%',
    top: '-100%',
    width: '1px',
    height: '1px',
    pointerEvents: 'none',
  })
  return video
}

export function useScreenWakeLock() {
  const sentinelRef = useRef<WakeLockSentinel | null>(null)
  const busyRef = useRef(false)
  const videoRef = useRef<HTMLVideoElement | null>(null)

  useEffect(() => {
    const hasWakeLock = 'wakeLock' in navigator

    const acquire = async () => {
      if (sentinelRef.current || busyRef.current || !hasWakeLock) return
      busyRef.current = true
      try {
        const s = await navigator.wakeLock.request('screen')
        sentinelRef.current = s
        s.addEventListener('release', () => {
          sentinelRef.current = null
          if (document.visibilityState === 'visible') acquire()
        })
      } catch {
      } finally {
        busyRef.current = false
      }
    }

    if (hasWakeLock) acquire()

    const onInteraction = () => {
      startWakeAudio()
      if (hasWakeLock) acquire()

      if (!videoRef.current) {
        const video = createWakeVideo()
        videoRef.current = video
        document.body.appendChild(video)
        video.play().catch(() => {})
      }

      document.removeEventListener('pointerdown', onInteraction)
    }

    const onVisibilityChange = () => {
      if (document.visibilityState !== 'visible') return
      if (hasWakeLock) acquire()
      const v = videoRef.current
      if (v?.paused) v.play().catch(() => {})
    }

    document.addEventListener('pointerdown', onInteraction)
    document.addEventListener('visibilitychange', onVisibilityChange)

    const interval = hasWakeLock ? window.setInterval(acquire, 15_000) : null

    return () => {
      document.removeEventListener('pointerdown', onInteraction)
      document.removeEventListener('visibilitychange', onVisibilityChange)
      if (interval !== null) clearInterval(interval)
      sentinelRef.current?.release()
      sentinelRef.current = null
      videoRef.current?.pause()
      videoRef.current?.remove()
      videoRef.current = null
      stopWakeAudio()
    }
  }, [])
}
